import sys
import json
import xml.etree.ElementTree as ET
import collections

# Get input data
start_x = input_data['start_x']
start_y = input_data['start_y']
target_x = input_data['target_x']
target_y = input_data['target_y']
autopress = input_data.get('autopress_buttons', False)

try:
    root = ET.fromstring(map_xml_string)
    width = int(root.get("width"))
    height = int(root.get("height"))
    grid = {}

    for row in root.findall("Row"):
        y = int(row.get("id"))
        for tile in row.findall("Tile"):
            x = int(tile.get("id"))
            t_type = tile.get("type")
            grid[(x, y)] = t_type

    start = (start_x, start_y)
    target = (target_x, target_y)

    if start not in grid or target not in grid:
        if autopress:
            print(json.dumps([]))
        else:
            print(json.dumps({"error": "Coordinates out of bounds or not in map data"}))
        exit()

    queue = collections.deque([[start]])
    visited = set([start])

    found = False
    final_path = []

    # Standard wall types to avoid
    WALL_TYPES = ["TYPE_2889", "TYPE_80fc", "TYPE_5519", "TYPE_a336"]

    while queue:
        path = queue.popleft()
        x, y = path[-1]

        if (x, y) == target:
            found = True
            final_path = path
            break

        for dx, dy in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
            nx, ny = x + dx, y + dy
            if 0 <= nx < width and 0 <= ny < height:
                if (nx, ny) not in visited:
                    tile_type = grid.get((nx, ny), "unseen")
                    if tile_type not in WALL_TYPES:
                        visited.add((nx, ny))
                        new_path = list(path)
                        new_path.append((nx, ny))
                        queue.append(new_path)

    if found:
        # Convert path to buttons
        buttons = []
        for i in range(len(final_path) - 1):
            curr = final_path[i]
            next_tile = final_path[i+1]
            dx = next_tile[0] - curr[0]
            dy = next_tile[1] - curr[1]
            if dx == 1: buttons.append("Right")
            elif dx == -1: buttons.append("Left")
            elif dy == 1: buttons.append("Down")
            elif dy == -1: buttons.append("Up")

        if autopress:
            print(json.dumps(buttons))
        else:
            # Return JSON object
            print(json.dumps({"found": True, "length": len(final_path), "path": str(final_path), "buttons": buttons}))
    else:
        if autopress:
            print(json.dumps([]))
        else:
            print(json.dumps({"found": False}))

except Exception as e:
    # Return valid JSON error or empty list
    if autopress:
        print(json.dumps([]))
    else:
        print(json.dumps({"error": str(e)}))

