def find_surf_start_point(map_xml_string, player_x, player_y, radius=10):
    import xml.etree.ElementTree as ET

    try:
        root = ET.fromstring(map_xml_string)
        width = int(root.attrib['width'])
        height = int(root.attrib['height'])

        # Helper to get tile type
        def get_tile_type(x, y):
            if 0 <= x < width and 0 <= y < height:
                row = root.find(f".//Row[@id='{y}']")
                if row is not None:
                    tile = row.find(f".//Tile[@id='{x}']")
                    if tile is not None:
                        return tile.attrib.get('type', 'unseen')
            return None

        # Common water types (add more if discovered)
        WATER_TYPES = ['TYPE_4e8c'] 
        # Common walkable types (add more if discovered)
        WALKABLE_TYPES = ['TYPE_3fe2', 'TYPE_fed7', 'TYPE_80fc'] 

        candidates = []

        for y in range(max(0, player_y - radius), min(height, player_y + radius + 1)):
            for x in range(max(0, player_x - radius), min(width, player_x + radius + 1)):
                current_type = get_tile_type(x, y)

                # If current tile is walkable
                if current_type in WALKABLE_TYPES:
                    # Check neighbors for water
                    neighbors = [
                        (x, y-1, "Up"),
                        (x, y+1, "Down"),
                        (x-1, y, "Left"),
                        (x+1, y, "Right")
                    ]

                    for nx, ny, direction in neighbors:
                        neighbor_type = get_tile_type(nx, ny)
                        if neighbor_type in WATER_TYPES:
                            dist = abs(player_x - x) + abs(player_y - y)
                            candidates.append({
                                "coordinate": (x, y),
                                "face_direction": direction,
                                "water_coordinate": (nx, ny),
                                "distance": dist
                            })
                            break # Only need one water neighbor to be valid

        # Sort by distance
        candidates.sort(key=lambda c: c['distance'])

        print(f"Found {len(candidates)} surf spots.")
        return candidates[:5] # Return top 5

    except Exception as e:
        return f"Error: {e}"

# Only map_xml_string is injected. We must pass it manually if we were running this locally, 
# but the system handles the injection for run_code. 
# For define_tool, this script body is what gets saved.

