import xml.etree.ElementTree as ET

def scan_map(map_xml_string, target_map_id, tile_types):
    try:
        root = ET.fromstring(map_xml_string)
        map_node = root.find(f".//Map[@id='{target_map_id}']")

        if not map_node:
            print(f"Map {target_map_id} not found in Mental Map.")
            return []

        if not tile_types:
            tile_types = ["TYPE_8564", "TYPE_201b", "TYPE_4a8b", "TYPE_5a4c"] # Common stairs/warps

        found_tiles = []
        print(f"--- Scanning Map {target_map_id} for {tile_types} ---")

        for row in map_node.findall("Row"):
            y = row.get("id")
            for tile in row.findall("Tile"):
                t_type = tile.get("type")
                x = tile.get("id")

                if t_type in tile_types:
                    print(f"FOUND: {t_type} at ({x}, {y})")
                    found_tiles.append({'x': int(x), 'y': int(y), 'type': t_type})

        if not found_tiles:
            print("No matching tiles found.")

        return found_tiles

    except Exception as e:
        print(f"Error parsing XML: {e}")
        return []

# Extract arguments
target_map_id = input_data.get('target_map_id')
tile_types = input_data.get('tile_types', [])

scan_map(map_xml_string, target_map_id, tile_types)

