import xml.etree.ElementTree as ET
import json

# Parse XML
root = ET.fromstring(map_xml_string)

# Default gates if not provided
default_gates = [[2, 6], [10, 6], [16, 6], [6, 8], [12, 8], [2, 10], [10, 10], [16, 10]]
gates = input_data.get('gate_coordinates')
if not gates:
    gates = default_gates

results = []

for pos in gates:
    x, y = pos[0], pos[1]
    # Find the tile
    tile = None
    for row in root.findall('Row'):
        if int(row.get('id')) == y:
            for t in row.findall('Tile'):
                if int(t.get('id')) == x:
                    tile = t
                    break
            break

    if tile is not None:
        t_type = tile.get('type')
        # Heuristic based on observation: 
        # TYPE_2889 is usually wall/closed gate
        # TYPE_3fe2 is floor/open gate
        state = "UNKNOWN"
        if t_type == "TYPE_2889":
            state = "CLOSED"
        elif t_type == "TYPE_3fe2":
            state = "OPEN"

        results.append({
            "coord": f"({x}, {y})",
            "type": t_type,
            "state": state
        })
    else:
        results.append({
            "coord": f"({x}, {y})",
            "type": "N/A",
            "state": "NOT_FOUND"
        })

print(json.dumps(results))
